// ddxSidecarFile is the YAML structure of a .ddx.yaml sidecar file.
type ddxSidecarFile struct {
	DDx ddxSidecarMeta `yaml:"ddx"`
}

type ddxSidecarMeta struct {
	ID          string          `yaml:"id"`
	Title       string          `yaml:"title"`
	MediaType   string          `yaml:"media_type"`
	Description string          `yaml:"description"`
	GeneratedBy *ddxGeneratedBy `yaml:"generated_by"`
}

type ddxGeneratedBy struct {
	RunID         string `yaml:"run_id"`
	PromptSummary string `yaml:"prompt_summary"`
	SourceHash    string `yaml:"source_hash"`
}

// Artifacts is the resolver for the artifacts query.
// It returns a paginated, optionally-filtered list of DDx-tracked artifacts
// for the given project. Documents come from the FEAT-007 doc graph; other
// artifacts come from .ddx.yaml sidecar files found under .ddx/plugins/.
func (r *queryResolver) Artifacts(ctx context.Context, projectID string, first *int, after *string, last *int, before *string, mediaType *string, search *string, sortKey *ArtifactSort, staleness *string, phase *string, prefix []string) (*ArtifactConnection, error) {
	root := r.projectRoot(ctx, projectID)

	artifacts, err := collectArtifacts(root)
	if err != nil {
		return nil, fmt.Errorf("collecting artifacts: %w", err)
	}

	// Apply mediaType filter (supports X/* wildcard suffix).
	if mediaType != nil && *mediaType != "" {
		mt := *mediaType
		filtered := artifacts[:0]
		if strings.HasSuffix(mt, "/*") {
			prefix := strings.TrimSuffix(mt, "*") // keep trailing slash
			for _, a := range artifacts {
				if strings.HasPrefix(a.MediaType, prefix) {
					filtered = append(filtered, a)
				}
			}
		} else {
			for _, a := range artifacts {
				if a.MediaType == mt {
					filtered = append(filtered, a)
				}
			}
		}
		artifacts = filtered
	}

	// Apply staleness filter.
	if staleness != nil && *staleness != "" {
		st := *staleness
		filtered := artifacts[:0]
		for _, a := range artifacts {
			if a.Staleness == st {
				filtered = append(filtered, a)
			}
		}
		artifacts = filtered
	}

	// Apply phase filter: matches when path is under docs/helix/<phase>/
	// where <phase> is either an exact match (e.g. "01-frame") or a numeric
	// prefix (e.g. "01") matching docs/helix/01-*/.
	if phase != nil && *phase != "" {
		ph := *phase
		filtered := artifacts[:0]
		for _, a := range artifacts {
			if matchesPhase(a.Path, ph) {
				filtered = append(filtered, a)
			}
		}
		artifacts = filtered
	}

	// Apply prefix filter (multi-value OR over id-prefix segments,
	// e.g. ADR, SD, FEAT, US, RSCH).
	if len(prefix) > 0 {
		set := make(map[string]struct{}, len(prefix))
		for _, p := range prefix {
			if p != "" {
				set[strings.ToUpper(p)] = struct{}{}
			}
		}
		if len(set) > 0 {
			filtered := artifacts[:0]
			for _, a := range artifacts {
				if _, ok := set[idPrefixSegment(a.ID)]; ok {
					filtered = append(filtered, a)
				}
			}
			artifacts = filtered
		}
	}

	// Apply search filter across title, path, description, frontmatter, and
	// body text per TD-029 precedence. Matches are recorded so each edge can
	// surface a context-window snippet on ArtifactEdge.snippet.
	matchSnippets := map[string]string{}
	if search != nil && *search != "" {
		q := strings.ToLower(*search)
		filtered := artifacts[:0]
		for _, a := range artifacts {
			snippet, ok := matchArtifactForSearch(a, root, q)
			if ok {
				filtered = append(filtered, a)
				matchSnippets[a.ID] = snippet
			}
		}
		artifacts = filtered
	}

	// Sort with (sortKey, id) tie-breaker for stable cursor pagination.
	sortArtifacts(artifacts, sortKey)

	// Build Relay edges.
	all := make([]*ArtifactEdge, len(artifacts))
	for i, a := range artifacts {
		cp := a
		edge := &ArtifactEdge{
			Node:   cp,
			Cursor: encodeStableCursor(cp.ID),
		}
		if sn, ok := matchSnippets[cp.ID]; ok && sn != "" {
			s := sn
			edge.Snippet = &s
		}
		all[i] = edge
	}

	startIdx := 0
	if after != nil {
		if afterID, ok := decodeStableCursor(*after); ok {
			for i, e := range all {
				if e.Node.ID == afterID {
					startIdx = i + 1
					break
				}
			}
		}
	}
	endIdx := len(all)
	if before != nil {
		if beforeID, ok := decodeStableCursor(*before); ok {
			for i, e := range all {
				if e.Node.ID == beforeID {
					endIdx = i
					break
				}
			}
		}
	}
	if startIdx > endIdx {
		startIdx = endIdx
	}

	windowSize := endIdx - startIdx
	slice := all[startIdx:endIdx]
	if first != nil && *first >= 0 && *first < len(slice) {
		slice = slice[:*first]
	}
	if last != nil && *last >= 0 && *last < len(slice) {
		slice = slice[len(slice)-*last:]
	}

	pageInfo := &PageInfo{
		HasPreviousPage: startIdx > 0 || (last != nil && *last >= 0 && *last < windowSize),
		HasNextPage:     endIdx < len(all) || (first != nil && *first >= 0 && *first < windowSize),
	}
	if len(slice) > 0 {
		pageInfo.StartCursor = &slice[0].Cursor
		pageInfo.EndCursor = &slice[len(slice)-1].Cursor
	}

	return &ArtifactConnection{
		Edges:      slice,
		PageInfo:   pageInfo,
		TotalCount: len(all),
	}, nil
}

// sortArtifacts orders artifacts by the requested sort key with a stable
// (sortKey, id) tie-breaker so cursor pagination is deterministic across
// pages even when the primary key has duplicate values.
func sortArtifacts(artifacts []*Artifact, key *ArtifactSort) {
	k := ArtifactSortPath
	if key != nil {
		k = *key
	}

// Shared URL-state helper for list views (artifacts, etc.).
// Reads/writes the well-known query params (q, mediaType, groupBy, sort,
// filters.*) while preserving any unrelated keys, including ?back=.

export type GroupBy = 'folder' | 'prefix' | 'mediaType' | 'workflowStage';

// Reserved facet URL keys (TD-006 facet contract):
//   q          — full-text search query (single)
//   mediaType  — media-type filter (single, supports X/* wildcard)
//   staleness  — staleness filter (single)
//   phase      — HELIX phase filter (single)
//   prefix     — id-prefix filter (multi: comma-separated)
//   sort       — sort key (single)
// groupBy is a Story-5 categorization axis (not a filter) and travels in
// the same URL but does NOT narrow results.
const KNOWN_KEYS = new Set(['q', 'mediaType', 'groupBy', 'sort', 'staleness', 'phase', 'prefix']);
const FILTER_PREFIX = 'filter.';

export interface ListURLState {
	q: string;
	mediaType: string | null;
	groupBy: GroupBy;
	sort: string | null;
	staleness: string | null;
	phase: string | null;
	prefix: string[];
	filters: Record<string, string>;
}

export const DEFAULT_GROUP_BY: GroupBy = 'folder';

function parseGroupBy(raw: string | null): GroupBy {
	if (raw === 'prefix' || raw === 'mediaType' || raw === 'folder' || raw === 'workflowStage')
		return raw;
	return DEFAULT_GROUP_BY;
}

export function readState(params: URLSearchParams): ListURLState {
	const filters: Record<string, string> = {};
	for (const [k, v] of params.entries()) {
		if (k.startsWith(FILTER_PREFIX)) filters[k.slice(FILTER_PREFIX.length)] = v;
	}
	const rawPrefix = params.get('prefix');
	const prefix = rawPrefix
		? rawPrefix
				.split(',')
				.map((s) => s.trim())
				.filter((s) => s.length > 0)
		: [];
	return {
		q: params.get('q') ?? '',
		mediaType: params.get('mediaType'),
		groupBy: parseGroupBy(params.get('groupBy')),
		sort: params.get('sort'),
		staleness: params.get('staleness'),
		phase: params.get('phase'),
		prefix,
		filters
	};
}

// writeState mutates a copy of `params` with the patch applied. Unrelated
// keys (including `back`) are preserved. Empty/null values delete the key.
export function writeState(params: URLSearchParams, patch: Partial<ListURLState>): URLSearchParams {
	const next = new URLSearchParams(params);

	if ('q' in patch) {
		if (patch.q) next.set('q', patch.q);
		else next.delete('q');
	}
	if ('mediaType' in patch) {
		if (patch.mediaType) next.set('mediaType', patch.mediaType);
		else next.delete('mediaType');
	}
	if ('groupBy' in patch) {
		if (patch.groupBy && patch.groupBy !== DEFAULT_GROUP_BY) next.set('groupBy', patch.groupBy);
		else next.delete('groupBy');
	}
	if ('sort' in patch) {
		if (patch.sort) next.set('sort', patch.sort);
		else next.delete('sort');
	}
	if ('staleness' in patch) {
		if (patch.staleness) next.set('staleness', patch.staleness);
		else next.delete('staleness');
	}
	if ('phase' in patch) {
		if (patch.phase) next.set('phase', patch.phase);
		else next.delete('phase');
	}
	if ('prefix' in patch) {
		const arr = patch.prefix ?? [];
		if (arr.length > 0) next.set('prefix', arr.join(','));
		else next.delete('prefix');
	}
	if ('filters' in patch && patch.filters) {
		// Replace only the filter.* keys; leave everything else intact.
		for (const k of Array.from(next.keys())) {
			if (k.startsWith(FILTER_PREFIX)) next.delete(k);
		}
		for (const [k, v] of Object.entries(patch.filters)) {
			if (v) next.set(FILTER_PREFIX + k, v);
		}
	}

	return next;
}

// Build a back-href that captures the current pathname + relevant search.
export function backHref(pathname: string, params: URLSearchParams): string {
	const s = params.toString();
	return s ? `${pathname}?${s}` : pathname;
}

export { KNOWN_KEYS, FILTER_PREFIX };

---TEST---
import { describe, it, expect } from 'vitest';
import { readState, writeState, backHref, DEFAULT_GROUP_BY } from './urlState';

describe('urlState.readState', () => {
	it('returns defaults for an empty URL', () => {
		const s = readState(new URLSearchParams(''));
		expect(s.q).toBe('');
		expect(s.mediaType).toBeNull();
		expect(s.groupBy).toBe(DEFAULT_GROUP_BY);
		expect(s.sort).toBeNull();
		expect(s.staleness).toBeNull();
		expect(s.phase).toBeNull();
		expect(s.prefix).toEqual([]);
		expect(s.filters).toEqual({});
	});

	it('parses all reserved facet keys (q, mediaType, staleness, phase, prefix, sort) plus groupBy', () => {
		const s = readState(
			new URLSearchParams(
				'q=foo&mediaType=text/markdown&staleness=fresh&phase=01-frame&prefix=ADR,FEAT&sort=TITLE&groupBy=workflowStage'
			)
		);
		expect(s.q).toBe('foo');
		expect(s.mediaType).toBe('text/markdown');
		expect(s.staleness).toBe('fresh');
		expect(s.phase).toBe('01-frame');
		expect(s.prefix).toEqual(['ADR', 'FEAT']);
		expect(s.sort).toBe('TITLE');
		expect(s.groupBy).toBe('workflowStage');
	});

	it('parses prefix as a comma-separated multi-value list and trims empties', () => {
		const s = readState(new URLSearchParams('prefix=ADR,,FEAT, US '));
		expect(s.prefix).toEqual(['ADR', 'FEAT', 'US']);
	});

	it('parses known keys and filter.* entries', () => {
		const s = readState(
			new URLSearchParams(
				'q=foo&mediaType=text/markdown&groupBy=prefix&sort=title&staleness=stale&filter.tag=v1'
			)
		);
		expect(s.q).toBe('foo');
		expect(s.mediaType).toBe('text/markdown');
		expect(s.groupBy).toBe('prefix');
		expect(s.sort).toBe('title');
		expect(s.staleness).toBe('stale');
		expect(s.filters).toEqual({ tag: 'v1' });
	});

	it('falls back to default groupBy on unknown values', () => {
		const s = readState(new URLSearchParams('groupBy=nonsense'));
		expect(s.groupBy).toBe(DEFAULT_GROUP_BY);
	});

	it('accepts the workflowStage axis in query params', () => {
		const s = readState(new URLSearchParams('groupBy=workflowStage'));
		expect(s.groupBy).toBe('workflowStage');
	});
});

describe('urlState.writeState', () => {
	it('preserves unrelated keys, including back', () => {
		const next = writeState(new URLSearchParams('back=/x?y=1&other=keep'), { q: 'hi' });
		expect(next.get('back')).toBe('/x?y=1');
		expect(next.get('other')).toBe('keep');
		expect(next.get('q')).toBe('hi');
	});

	it('drops groupBy when it equals the default', () => {
		const next = writeState(new URLSearchParams('groupBy=prefix'), { groupBy: 'folder' });
		expect(next.has('groupBy')).toBe(false);
	});

	it('round-trips workflowStage through the query string', () => {
		const next = writeState(new URLSearchParams(''), { groupBy: 'workflowStage' });
		expect(next.get('groupBy')).toBe('workflowStage');
		expect(readState(next).groupBy).toBe('workflowStage');
	});

	it('deletes keys when given empty/null values', () => {
		const next = writeState(new URLSearchParams('q=old&mediaType=x'), {
			q: '',
			mediaType: null
		});
		expect(next.has('q')).toBe(false);
		expect(next.has('mediaType')).toBe(false);
	});

	it('round-trips sort and staleness, and clears them on null', () => {
		const set = writeState(new URLSearchParams(''), { sort: 'TITLE', staleness: 'stale' });
		expect(set.get('sort')).toBe('TITLE');
		expect(set.get('staleness')).toBe('stale');
		expect(readState(set).sort).toBe('TITLE');
		expect(readState(set).staleness).toBe('stale');

		const cleared = writeState(set, { sort: null, staleness: null });
		expect(cleared.has('sort')).toBe(false);
		expect(cleared.has('staleness')).toBe(false);
	});

	it('round-trips phase and prefix, clears them on null/empty', () => {
		const set = writeState(new URLSearchParams(''), {
			phase: '01-frame',
			prefix: ['ADR', 'FEAT']
		});
		expect(set.get('phase')).toBe('01-frame');
		expect(set.get('prefix')).toBe('ADR,FEAT');
		expect(readState(set).phase).toBe('01-frame');
		expect(readState(set).prefix).toEqual(['ADR', 'FEAT']);

		const cleared = writeState(set, { phase: null, prefix: [] });
		expect(cleared.has('phase')).toBe(false);
		expect(cleared.has('prefix')).toBe(false);
	});

	it('composes phase and prefix with q/mediaType/staleness/sort without dropping any', () => {
		const next = writeState(new URLSearchParams(''), {
			q: 'spec',
			mediaType: 'text/markdown',
			staleness: 'fresh',
			phase: '02-design',
			prefix: ['ADR'],
			sort: 'TITLE'
		});
		expect(next.get('q')).toBe('spec');
		expect(next.get('mediaType')).toBe('text/markdown');
		expect(next.get('staleness')).toBe('fresh');
		expect(next.get('phase')).toBe('02-design');
		expect(next.get('prefix')).toBe('ADR');
		expect(next.get('sort')).toBe('TITLE');
	});

	it('replaces filter.* entries atomically', () => {
		const next = writeState(new URLSearchParams('filter.a=1&filter.b=2&q=keep'), {
			filters: { c: '3' }
		});
		expect(next.has('filter.a')).toBe(false);
		expect(next.has('filter.b')).toBe(false);
		expect(next.get('filter.c')).toBe('3');
		expect(next.get('q')).toBe('keep');
	});
});

describe('urlState.backHref', () => {
	it('omits the trailing ? when there are no params', () => {
		expect(backHref('/x', new URLSearchParams(''))).toBe('/x');
